class Solution:
    def maxScore(self, nums: List[int], x: int) -> int:
        even = nums[0] if nums[0] % 2 == 0 else -x
        odd = nums[0] if nums[0] % 2 == 1 else -x

        for i in range(1, len(nums)):
            if nums[i] % 2 == 0:
                even = max(even + nums[i], odd + nums[i] - x)
            else:
                odd = max(odd + nums[i], even + nums[i] - x)

        return max(even, odd)
